class Solution {
public:
    string concatHex36(int n) {
        long long n2 = static_cast<long long>(n) * n;
        long long n3 = n2 * n;
        string hex = toHex(n2);
        string hexatrigesimal = toHexatrigesimal(n3);
        return hex + hexatrigesimal;
    }

    string toHex(long long num) {
        string result;
        string hexMap = "0123456789ABCDEF";
        while (num > 0) {
            result = hexMap[num % 16] + result;
            num /= 16;
        }
        return result;
    }

    string toHexatrigesimal(long long num) {
        string result;
        string hexatrigesimalMap = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
        while (num > 0) {
            result = hexatrigesimalMap[num % 36] + result;
            num /= 36;
        }
        return result;
    }
};
